<script>
import HasCards from 'laravel-nova/src/mixins/HasCards';
import BreadCrumb from './BreadCrumb'
export default {
    mixins: [HasCards],
    props: {
        dashboardName: {
            type: String,
            required: false,
            default: 'main',
        },
        textAlign : {
            type : String ,
            default : "text-left"
        }
    },
    components : {
        BreadCrumb
    },
    watch: {
        cardsEndpoint() {
            this.fetchCards()
        }
    },
    computed: {
        cardsEndpoint() {
            return `/nova-vendor/AlexBowers/nova-multiple-dashboard/dashboards/${this.dashboardName}`
        },
    },
    methods: {
        goTo(type){

            if (type == 'deposit' || type == 'withdraw') {

                this.$router.push({name: 'transactions-feature.' + type})

            }

            this.$router.push({name: 'transactions-feature.' + type})
        }
    },

    mounted() {

        let lang = Nova.config.local ;
        lang == 'en' ? this.textAlign = 'text-left' : this.textAlign = 'text-right' ;

    }

}
</script>

